{
    private CancellationTokenSource? _cts;
    private Task? _workerTask;

    public void Start()
    {
        if (_workerTask is { IsCompleted: false })
            throw new InvalidOperationException("Processor is already running.");

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // LongRunning hints the scheduler to use a dedicated thread,
        // matching the original Thread.IsBackground = true behavior
        // for a loop that runs for the lifetime of the app.
        _workerTask = Task.Factory.StartNew(
            () => ProcessLoop(token),
            token,
            TaskCreationOptions.LongRunning,
            TaskScheduler.Default);
    }

    private void ProcessLoop(CancellationToken token)
    {
