                // so there is no need for ResetAbort(). The finally block
                // below runs normally, then the while-loop condition exits.
                RollbackCurrentTransaction();
                break; // exit the loop (no equivalent of ResetAbort needed)
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

