        _cts.Cancel();

        // Wait for the worker to finish, with a timeout.
        // This replaces the Thread.Sleep(2000) + Thread.Abort() pattern.
        // If the task doesn't finish in time, we log/warn but do NOT
        // force-kill — there is no safe equivalent of Abort() in .NET 8.
        var completed = await Task.WhenAny(
            _workerTask,
            Task.Delay(TimeSpan.FromSeconds(2)));

        if (completed != _workerTask)
        {
            // Worker didn't finish in time. In .NET 8 you cannot force-
            // abort it. Investigate why it's not observing the token.
            Console.Error.WriteLine(
                "WARNING: BackgroundProcessor did not stop within 2 seconds.");
        }
